// Parse the request body and validate the Xquik API key.
const root = $json ?? {};
const body = root.body && typeof root.body === 'object' ? root.body : root;

const queryRaw = body.query ?? body.q ?? '';
const query = queryRaw.toString().trim();

if (!query) {
  throw new Error('Missing body.query');
}

const apiKey = ($env.XQUIK_API_KEY ?? '').toString().trim();
if (!apiKey) {
  throw new Error('Missing XQUIK_API_KEY environment variable');
}

const limitRaw = Number(body.limit ?? 20);
const limit = Number.isFinite(limitRaw)
  ? Math.min(Math.max(Math.trunc(limitRaw), 1), 50)
  : 20;

const queryTypeRaw = body.queryType ?? 'Latest';
const queryType = queryTypeRaw === 'Top' ? 'Top' : 'Latest';

return [{ json: { query, limit, queryType } }];

// Convert Xquik search results into a compact LLM prompt.
const response = $json ?? {};
const rows = response.data ?? response.tweets ?? response.items ?? response.results ?? [];
const tweets = Array.isArray(rows) ? rows : [];

const cleanText = (value) => {
  return (value ?? '').toString().replace(/\s+/g, ' ').trim();
};

const asHandle = (value) => {
  const text = cleanText(value);
  return text ? text.replace(/^@/, '') : 'unknown';
};

const summarizeMetrics = (tweet) => {
  const metrics = tweet.metrics ?? tweet.public_metrics ?? {};
  const likes = metrics.like_count ?? metrics.likes ?? tweet.like_count ?? tweet.likes;
  const retweets = metrics.retweet_count ?? metrics.retweets ?? tweet.retweet_count ?? tweet.retweets;
  const replies = metrics.reply_count ?? metrics.replies ?? tweet.reply_count ?? tweet.replies;

  const parts = [];
  if (likes !== undefined) parts.push(`${likes} likes`);
  if (retweets !== undefined) parts.push(`${retweets} retweets`);
  if (replies !== undefined) parts.push(`${replies} replies`);

  return parts.join(', ');
};

const posts = tweets
  .slice(0, 20)
  .map((tweet, index) => {
    const author = asHandle(
      tweet.author?.username ??
        tweet.user?.username ??
        tweet.username ??
        tweet.author_username ??
        tweet.screen_name
    );
    const text = cleanText(tweet.text ?? tweet.full_text ?? tweet.content ?? tweet.description);
    const metrics = summarizeMetrics(tweet);
    const suffix = metrics ? ` (${metrics})` : '';
    return text ? `${index + 1}. @${author}: ${text}${suffix}` : '';
  })
  .filter(Boolean);

if (posts.length === 0) {
  throw new Error('Xquik returned no tweets for this query');
}

const query = $node['Parse Input'].json.query;
const prompt = [
  'You are a concise social research assistant.',
  'Use only the X search results below.',
  `Query: ${query}`,
  '',
  posts.join('\n'),
  '',
  'Return:',
  '1. A 3 sentence context brief.',
  '2. 3 actionable observations.',
  '3. 3 search refinements for the next run.',
].join('\n');

const apiBase = $env.OPENAI_API_BASE || 'http://host.docker.internal:1234/v1';
const model = $env.OPENAI_MODEL || 'openai/gpt-oss-20b';

return [
  {
    json: {
      query,
      post_count: posts.length,
      prompt,
      apiUrl: apiBase + '/chat/completions',
      headers: {
        Authorization: 'Bearer ' + ($env.OPENAI_API_KEY || 'lm-studio'),
        'Content-Type': 'application/json',
      },
      payload: {
        model,
        temperature: 0.2,
        max_tokens: 700,
        messages: [
          {
            role: 'system',
            content: 'Summarize social signals with neutral, evidence-bound wording.',
          },
          { role: 'user', content: prompt },
        ],
      },
    },
  },
];

// Normalize the OpenAI-compatible response.
const choice = $json.choices?.[0] ?? {};
const raw = choice.message?.content ?? choice.text ?? '';
const brief = raw.toString().replace(/<\|[^>]+?\|>/g, '').trim();

return [
  {
    json: {
      query: $node['Build Brief Prompt'].json.query,
      post_count: $node['Build Brief Prompt'].json.post_count,
      model: $node['Build Brief Prompt'].json.payload.model,
      brief,
    },
  },
];
